class MinionCard {
  constructor() {
    this.attack = 2;
    this.health = 2;

    this.auras = [];
  }

  applyAuras() {
    for(const aura of this.auras) {
      aura.trigger(this);
    }
  }
}

class AuraMinionAttack extends MinionCard {
  constructor() {
    super();

    this.auras.push({
      trigger: (minion) => {
        if(minion === this) {
          // This minion gets the aura too, so we add the attack bonus to itself
          minion.attack += 1;
        } else {
          // Other friendly minions get the aura
          minion.attack += 1;
        }
      }
    });
  }
}

class AuraMinionCost extends MinionCard {
  constructor() {
    super();

    this.auras.push({
      trigger: (minion) => {
        // Count the number of friendly minions on the board
        const friendlyMinionCount = player.board.filter((boardMinion) => boardMinion != this).length;

        // Reduce the cost of this minion accordingly
        this.cost = Math.max(0, this.originalCost - friendlyMinionCount);
      }
    });
  }
}

class AuraMinionCostReduction extends MinionCard {
  constructor() {
    super();

    this.auras.push({
      trigger: (minion) => {
        // Reduce the cost of other minions in the player's hand by 1
        const otherMinions = player.hand.filter((handMinion) => handMinion != minion);
        for(const otherMinion of otherMinions) {
          otherMinion.cost -= 1;
        }
      }
    });
  }
}

